// Helper to parse dates to standard YYYY-MM-DD
function parseDate(pubDateStr) {
  if (!pubDateStr) return null;
  try {
    const d = new Date(pubDateStr);
    if (isNaN(d.getTime())) return null;
    return d.toISOString().split('T')[0];
  } catch (e) {
    return null;
  }
}

// Helper to safely extract the publisher name from parsed XML source tag
function getPublisher(source) {
  if (!source) return 'Google News';
  if (typeof source === 'string') return source;
  if (source.$) return source.$; // xml2js standard text content accessor
  if (source._) return source._;
  return 'Google News';
}

// Helper to extract items from parsed XML JSON structure safely
function extractRssItems(xmlNodeName) {
  try {
    const data = $(xmlNodeName).all();
    if (!data || data.length === 0) return [];

    const root = data[0].json;
    if (!root || !root.rss || !root.rss.channel) {
      console.warn(`No valid XML channel data in node ${xmlNodeName}`);
      return [];
    }

    const items = root.rss.channel.item;
    if (!items) return [];

    return Array.isArray(items) ? items : [items];
  } catch (error) {
    console.error(`Error extracting items from ${xmlNodeName}:`, error);
    return [];
  }
}

// Extract items from each parsed RSS stream
const fundingRaw = extractRssItems('Parse Funding XML');
const expansionRaw = extractRssItems('Parse Expansion XML');
const acquisitionRaw = extractRssItems('Parse Acquisition XML');

const standardizedArticles = [];

// Helper to map raw XML items to the standardized contract object
function mapToContract(item, signalType) {
  return {
    json: {
      title: item.title || null,
      description: item.description || null,
      sourceUrl: item.link,
      articleDate: parseDate(item.pubDate),
      buyingSignal: signalType,
      source: getPublisher(item.source)
    }
  };
}

// Map and tag funding items
for (const item of fundingRaw) {
  if (item.link) {
    standardizedArticles.push(mapToContract(item, 'Funding'));
  }
}

// Map and tag expansion items
for (const item of expansionRaw) {
  if (item.link) {
    standardizedArticles.push(mapToContract(item, 'Expansion'));
  }
}

// Map and tag acquisition items
for (const item of acquisitionRaw) {
  if (item.link) {
    standardizedArticles.push(mapToContract(item, 'Acquisition'));
  }
}

// Output standardized contract objects
return standardizedArticles;

// Helper to normalize URLs (strips query parameters, anchors, lowercase, and trailing slashes)
function normalizeUrl(url) {
  if (!url || typeof url !== 'string') return '';
  try {
    let decoded = decodeURIComponent(url);
    let cleanUrl = decoded.split('?')[0];
    cleanUrl = cleanUrl.split('#')[0];
    cleanUrl = cleanUrl.toLowerCase().trim();
    // Remove protocol and standard www subdomains
    cleanUrl = cleanUrl.replace(/^(https?:\/\/)?(www\.)?/, '');
    if (cleanUrl.endsWith('/')) {
      cleanUrl = cleanUrl.slice(0, -1);
    }
    return cleanUrl;
  } catch (e) {
    let clean = url.split('?')[0].split('#')[0].toLowerCase().trim();
    clean = clean.replace(/^(https?:\/\/)?(www\.)?/, '');
    if (clean.endsWith('/')) {
      clean = clean.slice(0, -1);
    }
    return clean;
  }
}

// 1. Fetch standardized articles from the previous step
const mergedArticles = $('Merge & Tag Feeds').all();

// 2. Fetch existing URLs from sheet database (L:L range is output from parent node)
let sheetRows = [];
try {
  sheetRows = $input.all();
} catch (error) {
  console.warn('Could not read existing URLs from Google Sheet:', error);
}

// 3. Extract and normalize existing database URLs
const existingUrls = new Set();
for (const row of sheetRows) {
  if (row.json) {
    // Column L header is "Source URL"
    const rawUrl = row.json['Source URL'] || row.json['sourceUrl'] || row.json['url'];
    if (rawUrl) {
      existingUrls.add(normalizeUrl(rawUrl));
    }
  }
}

// 4. Perform stateful deduplication
const uniqueNewItems = [];
const seenInRun = new Set();
let duplicateCount = 0;

for (const item of mergedArticles) {
  const rawUrl = item.json.sourceUrl;
  if (!rawUrl) continue;

  const normUrl = normalizeUrl(rawUrl);

  // Filter out duplicates within the run and existing sheet records
  if (seenInRun.has(normUrl) || existingUrls.has(normUrl)) {
    duplicateCount++;
    continue;
  }

  seenInRun.add(normUrl);

  // Forward item adhering strictly to the contract
  uniqueNewItems.push({
    json: {
      title: item.json.title,
      description: item.json.description,
      sourceUrl: item.json.sourceUrl,
      articleDate: item.json.articleDate,
      buyingSignal: item.json.buyingSignal,
      source: item.json.source,
      normalizedUrl: normUrl
    }
  });
}

// 5. Execution Logging to console (n8n Execution History capture)
console.log('--- MODULE 1 EXECUTION METRICS ---');
console.log(`Total RSS Articles Fetched: ${mergedArticles.length}`);
console.log(`Duplicate Articles Removed: ${duplicateCount}`);
console.log(`New Unique Articles Forwarded: ${uniqueNewItems.length}`);
console.log('----------------------------------');

// 6. Embed execution summary metadata on items for debugging downstream
for (const item of uniqueNewItems) {
  item.json.meta = {
    totalFetched: mergedArticles.length,
    duplicatesRemoved: duplicateCount,
    newForwarded: uniqueNewItems.length
  };
}

return uniqueNewItems;

// Helper to extract text from various possible n8n HTTP Request node output formats
function extractScrapeText(input) {
  if (!input) return null;
  if (typeof input === 'string') return input;
  // Check common n8n HTTP Request properties
  const content = input.body || input.data || input.content || input.json || input.text;
  if (content) {
    if (typeof content === 'string') return content;
    if (typeof content === 'object') return JSON.stringify(content);
  }
  // Fallback scan of first string property in case of non-standard object key
  for (const key of Object.keys(input)) {
    if (typeof input[key] === 'string' && input[key].trim().length > 0) {
      if (['error', 'statusCode', 'statusMessage', 'message'].includes(key)) continue;
      return input[key];
    }
  }
  return null;
}

// Helper to resolve Google News redirects
async function resolveGoogleRedirect(url) {
  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 6000);
    const response = await fetch(url, {
      method: 'GET',
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
      },
      signal: controller.signal
    });
    clearTimeout(timeoutId);
    return response.url || url;
  } catch (err) {
    console.warn(`Failed to resolve Google redirect for ${url}:`, err);
    return url;
  }
}

// Helper to fetch directly from Jina Reader
async function scrapeWithJina(targetUrl) {
  try {
    const jinaUrl = `https://r.jina.ai/${targetUrl}`;
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 6000);
    const response = await fetch(jinaUrl, {
      method: 'GET',
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
      },
      signal: controller.signal
    });
    clearTimeout(timeoutId);
    if (response.ok) {
      return await response.text();
    }
    return null;
  } catch (err) {
    console.warn(`Failed to scrape resolved URL ${targetUrl} via Jina:`, err);
    return null;
  }
}

// Helper to check for scraper blocks, empty content, or failures
function isFailedScrape(text, result) {
  if (result && (result.error || result.statusCode >= 400)) {
    return true;
  }
  // Check if content length is under the 300 character cutoff
  if (!text || text.trim().length < 300) {
    return true;
  }
  const lowercaseContent = text.toLowerCase();
  for (const signal of BLOCK_SIGNALS) {
    if (lowercaseContent.includes(signal)) {
      return true;
    }
  }
  return false;
}

// Helper to clean scraped markdown text and remove boilerplate
function cleanMarkdown(text) {
  if (!text) return '';
  return text
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .split('\n')
    .filter(line => {
      const trimmed = line.toLowerCase().trim();
      for (const pattern of BOILERPLATE_PATTERNS) {
        if (trimmed.includes(pattern)) {
          return false;
        }
      }
      return true;
    })
    .join('\n')
    .trim();
}

// Helper to truncate text safely at paragraph, sentence, or word boundaries
function truncateToLimit(text, maxChars) {
  if (!text || text.length <= maxChars) return text;
  let cutPos = maxChars;
  const chunk = text.slice(0, maxChars);
  let boundary = chunk.lastIndexOf('\n\n');
  if (boundary > maxChars * 0.8) {
    cutPos = boundary;
  } else {
    boundary = chunk.lastIndexOf('. ');
    if (boundary > maxChars * 0.8) {
      cutPos = boundary + 1;
    } else {
      boundary = chunk.lastIndexOf(' ');
      if (boundary > maxChars * 0.8) {
        cutPos = boundary;
      }
    }
  }
  return text.slice(0, cutPos).trim() + '\n\n[Content truncated due to size limits...]';
}

// Helper to generate dynamic processed timestamp
function getTimestamp() {
  const now = new Date();
  const pad = (num) => String(num).padStart(2, '0');
  return `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())} ${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;
}

// MAIN HANDLER INITIATION
const scrapeInput = $input.item.json;
const originalArticle = $('Loop Over Leads').item.json;

const BLOCK_SIGNALS = [
  'cloudflare', 'enable javascript', 'captcha', 'access denied',
  '403 forbidden', 'error 1020', 'paywall', 'accept cookies',
  'cookie wall', 'robot detection', 'just a moment'
];

const BOILERPLATE_PATTERNS = [
  'cookie settings', 'privacy policy', 'terms of use', 'all rights reserved',
  'advertisement', 'sponsored', 'read more', 'related articles',
  'share this article', 'newsletter', 'subscribe', 'copyright',
  'share on facebook', 'share on twitter', 'share on linkedin',
  'newsletter signup', 'email newsletter', 'cookie notice', 'cookie policy'
];

const rawScrapedText = extractScrapeText(scrapeInput);
let contentSource = 'Jina';
let finalContent = '';
let scrapeQuality = 'High';
let targetUrl = originalArticle.sourceUrl;
let failed = isFailedScrape(rawScrapedText, scrapeInput);

if (failed) {
  console.log(`[Scrape Fail] Scrape failed for: ${originalArticle.sourceUrl}. Attempting redirect resolution...`);
  const resolvedUrl = await resolveGoogleRedirect(originalArticle.sourceUrl);
  if (resolvedUrl && resolvedUrl !== originalArticle.sourceUrl) {
    console.log(`[Redirect Resolved] Final URL: ${resolvedUrl}. Retrying Jina Scrape...`);
    const retriedText = await scrapeWithJina(resolvedUrl);
    const cleanedRetried = cleanMarkdown(retriedText);
    if (cleanedRetried && cleanedRetried.length >= 300) {
      const isBlock = BLOCK_SIGNALS.some(signal => cleanedRetried.toLowerCase().includes(signal));
      if (!isBlock) {
        contentSource = 'Jina (Resolved)';
        targetUrl = resolvedUrl;
        finalContent = cleanedRetried;
        failed = false;
        console.log(`[Scrape Success] Jina successfully scraped resolved URL: ${resolvedUrl}`);
      }
    }
  }
} else {
  finalContent = cleanMarkdown(rawScrapedText);
}

if (failed) {
  contentSource = 'RSS';
  scrapeQuality = 'Fallback';
  finalContent = `${originalArticle.title}\n\n${originalArticle.description || ''}`.trim();
  console.warn(`[Fallback Activated] All scraping options failed. Using RSS Snippet for: ${originalArticle.sourceUrl}`);
} else {
  finalContent = truncateToLimit(finalContent, 8000);
  scrapeQuality = finalContent.length >= 1500 ? 'High' : 'Medium';
}

const estimatedTokens = Math.ceil(finalContent.length / 4);

const outputContract = {
  json: {
    title: originalArticle.title,
    description: originalArticle.description,
    sourceUrl: targetUrl,
    normalizedUrl: originalArticle.normalizedUrl,
    articleDate: originalArticle.articleDate,
    buyingSignal: originalArticle.buyingSignal,
    source: originalArticle.source,
    contentSource: contentSource,
    articleContent: finalContent,
    contentLength: finalContent.length,
    estimatedTokens: estimatedTokens,
    scrapeQuality: scrapeQuality,
    ingestedAt: getTimestamp()
  }
};

console.log('--- MODULE 2 STATUS ---');
console.log(`URL: ${targetUrl}`);
console.log(`Scrape Result: ${contentSource.includes('Jina') ? 'SUCCESS' : 'FAILED (RSS Fallback)'}`);
console.log(`Scrape Source: ${contentSource}`);
console.log(`Scrape Quality: ${scrapeQuality}`);
console.log(`Final Content Length: ${finalContent.length} chars`);
console.log(`Estimated Tokens: ${estimatedTokens}`);
console.log('-----------------------');

return [outputContract];

const groqResult = $input.item.json;
const originalLead = $('Handle Scrape Fallback').item.json;

function getTimestamp() {
  const now = new Date();
  const pad = (num) => String(num).padStart(2, '0');
  return `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())} ${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;
}

// Robust normalization helpers
function normalizeString(val) {
  if (val === null || val === undefined) return null;
  if (Array.isArray(val)) return val.map(s => String(s).trim()).filter(s => s !== '').join(', ');
  const s = String(val).trim();
  return s === '' || s.toLowerCase() === 'null' ? null : s;
}

function normalizeArray(val) {
  if (val === null || val === undefined) return null;
  if (Array.isArray(val)) {
    const clean = val.map(s => String(s).trim()).filter(s => s !== '' && s.toLowerCase() !== 'null');
    return clean.length > 0 ? clean.join(', ') : null;
  }
  return normalizeString(val);
}

function normalizeNumber(val, defaultVal = 5) {
  if (val === null || val === undefined) return defaultVal;
  const num = parseInt(val, 10);
  return isNaN(num) ? defaultVal : num;
}

let aiContent = {};
let parseSuccess = true;

try {
  let rawContent = '';
  if (groqResult.choices && groqResult.choices[0] && groqResult.choices[0].message) {
    rawContent = groqResult.choices[0].message.content || '';
  } else if (typeof groqResult === 'string') {
    rawContent = groqResult;
  } else {
    rawContent = JSON.stringify(groqResult);
  }

  // Extract JSON block using regex
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    rawContent = jsonMatch[0];
  }

  aiContent = JSON.parse(rawContent);
} catch (e) {
  console.error("Failed to parse Groq AI response:", e);
  parseSuccess = false;

  // Safe defaults
  aiContent = {
    companyName: originalLead.title ? originalLead.title.split(' ')[0] : 'Unknown',
    founders: null,
    businessEvent: 'AI Parsing Error: raw output could not be read as JSON.',
    companyStage: 'Unknown',
    recommendedServices: [],
    confidence: 5,
    leadQuality: 'Medium',
    qualificationReason: `Failed to parse LLM response. Original description: ${originalLead.description || 'N/A'}. Check execution logs.`,
    riskFactors: [],
    nextAdvisoryOpportunity: 'Manual review required'
  };
}

// Apply normalization to guarantee database contracts
const companyName = normalizeString(aiContent.companyName) || normalizeString(originalLead.title ? originalLead.title.split(' ')[0] : null) || 'Unknown';
const founders = normalizeArray(aiContent.founders);
const businessEvent = normalizeString(aiContent.businessEvent) || normalizeString(originalLead.description) || 'Unknown Event';
const companyStage = normalizeString(aiContent.companyStage);
const recommendedServices = normalizeArray(aiContent.recommendedServices) || 'General Consultation';
const confidence = normalizeNumber(aiContent.confidence, 5);
const leadQuality = normalizeString(aiContent.leadQuality) || (confidence >= 7 ? 'High' : (confidence >= 4 ? 'Medium' : 'Low'));
const qualificationReason = normalizeString(aiContent.qualificationReason) || 'No analysis reasons provided by AI.';
const riskFactors = normalizeArray(aiContent.riskFactors);
const nextAdvisoryOpportunity = normalizeString(aiContent.nextAdvisoryOpportunity) || 'General Consultation';

console.log('--- MODULE 3 STATUS ---');
console.log(`Groq Ingestion Status: ${parseSuccess ? 'SUCCESS' : 'FAILED (Safe Defaults Used)'}`);
console.log(`Company Name: ${companyName}`);
console.log(`Confidence: ${confidence}`);
console.log(`Lead Quality: ${leadQuality}`);
console.log('-----------------------');

return [{
  json: {
    companyName: companyName,
    founders: founders,
    businessEvent: businessEvent,
    companyStage: companyStage,
    recommendedServices: recommendedServices,
    leadQuality: leadQuality,
    confidence: confidence,
    qualificationReason: qualificationReason,
    riskFactors: riskFactors,
    nextAdvisoryOpportunity: nextAdvisoryOpportunity,
    articleDate: originalLead.articleDate || normalizeString(aiContent.articleDate) || 'Unknown',
    sourceUrl: originalLead.sourceUrl,
    processedTimestamp: getTimestamp()
  }
}];
